import { type NextRequest } from "next/server"
import { track } from "@vercel/analytics/server"

import { parseDesignSystemConfig } from "@/app/(create)/init/parse-config"

import { buildInstructions } from "./build-instructions"

export async function GET(request: NextRequest) {
  try {
    const searchParams = request.nextUrl.searchParams
    const result = parseDesignSystemConfig(searchParams)

    if (!result.success) {
      return new Response(result.error, { status: 400 })
    }

    track("create_app_manual", result.data)

    const markdown = buildInstructions(result.data)

    return new Response(markdown, {
      headers: { "Content-Type": "text/markdown; charset=utf-8" },
    })
  } catch (error) {
    return new Response(
      error instanceof Error ? error.message : "An unknown error occurred",
      { status: 500 }
    )
  }
}

import type { Access, AccessResult } from '../config/types.js'
import type { PayloadRequest } from '../types/index.js'

import { Forbidden } from '../errors/index.js'

type OperationArgs = {
  data?: any
  disableErrors?: boolean
  id?: number | string
  isReadingStaticFile?: boolean
  req: PayloadRequest
}
export const executeAccess = async (
  { id, data, disableErrors, isReadingStaticFile = false, req }: OperationArgs,
  access: Access,
): Promise<AccessResult> => {
  if (access) {
    const resolvedConstraint = await access({
      id,
      data,
      isReadingStaticFile,
      req,
    })

    if (!resolvedConstraint) {
      if (!disableErrors) {
        throw new Forbidden(req.t)
      }
    }

    return resolvedConstraint
  }

  if (req.user) {
    return true
  }

  if (!disableErrors) {
    throw new Forbidden(req.t)
  }
  return false
}

import type { Where } from '../../types/index.js'
import type { PreferenceUpdateRequest } from '../types.js'

import { UnauthorizedError } from '../../errors/UnauthorizedError.js'
import { preferencesCollectionSlug } from '../config.js'

export async function update(args: PreferenceUpdateRequest) {
  const {
    key,
    req: { payload },
    req,
    user,
    value,
  } = args

  if (!user) {
    throw new UnauthorizedError(req.t)
  }

  const where: Where = {
    and: [
      { key: { equals: key } },
      { 'user.value': { equals: user.id } },
      { 'user.relationTo': { equals: user.collection } },
    ],
  }

  const preference = {
    key,
    user: {
      relationTo: user.collection,
      value: user.id,
    },
    value,
  }

  return await payload.db.upsert({
    collection: preferencesCollectionSlug,
    data: preference,
    req,
    where,
  })
}

import {cache} from 'react';
import type {Locale, useMessages as useMessagesType} from 'use-intl';
import getConfig from './getConfig.js';

export function getMessagesFromConfig(
  config: Awaited<ReturnType<typeof getConfig>>
): ReturnType<typeof useMessagesType> {
  if (!config.messages) {
    throw new Error(
      'No messages found. Have you configured them correctly? See https://next-intl.dev/docs/configuration#messages'
    );
  }
  return config.messages;
}

async function getMessagesCachedImpl(locale?: Locale) {
  const config = await getConfig(locale);
  return getMessagesFromConfig(config);
}
const getMessagesCached = cache(getMessagesCachedImpl);

export default async function getMessages(opts?: {
  locale?: Locale;
}): Promise<ReturnType<typeof useMessagesType>> {
  return getMessagesCached(opts?.locale);
}

// TypeScript trick to simulate opaque types, like in Flow.
type Opaque<K, T> = T & { __brand: K }

// Only functions in this module should be allowed to create CacheKeys.
export type NormalizedPathname = Opaque<'NormalizedPathname', string>
export type NormalizedSearch = Opaque<'NormalizedSearch', string>
export type NormalizedNextUrl = Opaque<'NormalizedNextUrl', string>

export type RouteCacheKey = Opaque<
  'RouteCacheKey',
  {
    pathname: NormalizedPathname
    search: NormalizedSearch
    nextUrl: NormalizedNextUrl | null

    // TODO: Eventually the dynamic params will be added here, too.
  }
>

export function createCacheKey(
  originalHref: string,
  nextUrl: string | null
): RouteCacheKey {
  const originalUrl = new URL(originalHref)
  const cacheKey = {
    pathname: originalUrl.pathname as NormalizedPathname,
    search: originalUrl.search as NormalizedSearch,
    nextUrl: nextUrl as NormalizedNextUrl | null,
  } as RouteCacheKey
  return cacheKey
}

// Bundled WebAssembly helper for the browser (DOM) runtime. Loaded on demand by
// the generated wasm loader instead of living in the default runtime.
//
// The wasm file is fetched relative to the chunk base path via the shared
// `__turbopack_chunk_relative_url__` runtime primitive. `edgeModule` is unused in
// the DOM runtime (the wasm is fetched, not provided as a global).
declare const __turbopack_chunk_relative_url__: (chunkPath: string) => string

export async function instantiate(
  chunkPath: string,
  imports: WebAssembly.Imports
): Promise<WebAssembly.Exports> {
  const req = fetch(__turbopack_chunk_relative_url__(chunkPath))
  const { instance } = await WebAssembly.instantiateStreaming(req, imports)
  return instance.exports
}

export async function compileModule(
  chunkPath: string
): Promise<WebAssembly.Module> {
  const req = fetch(__turbopack_chunk_relative_url__(chunkPath))
  return await WebAssembly.compileStreaming(req)
}

import type AbstractIntlMessages from './AbstractIntlMessages.js';
import type {InitializedIntlConfig} from './IntlConfig.js';
import type {NestedKeyOf} from './MessageKeys.js';
import createBaseTranslator from './createBaseTranslator.js';
import type {Formatters, IntlCache} from './formatters.js';
import resolveNamespace from './resolveNamespace.js';

export type CreateTranslatorImplProps<Messages> = Omit<
  InitializedIntlConfig,
  'messages'
> & {
  namespace: string;
  messages: Messages;
  formatters: Formatters;
  cache: IntlCache;
};

export default function createTranslatorImpl<
  Messages extends AbstractIntlMessages,
  NestedKey extends NestedKeyOf<Messages>
>(
  {messages, namespace, ...rest}: CreateTranslatorImplProps<Messages>,
  namespacePrefix: string
) {
  // The `namespacePrefix` is part of the type system.
  // See the comment in the function invocation.
  messages = messages[namespacePrefix] as Messages;
  namespace = resolveNamespace(namespace, namespacePrefix) as NestedKey;

  return createBaseTranslator<Messages, NestedKey>({
    ...rest,
    messages,
    namespace
  });
}

import {getPresets} from 'eslint-config-molindo';
import reactCompilerPlugin from 'eslint-plugin-react-compiler';

export default (await getPresets('typescript', 'react', 'vitest')).concat({
  plugins: {
    'react-compiler': reactCompilerPlugin
  },
  rules: {
    'react-compiler/react-compiler': 'error',
    'no-restricted-imports': [
      'error',
      {
        paths: [
          {
            // Because:
            // - Avoid hardcoding the `locale` param
            // - Prepare for a new API in Next.js to read params deeply
            // - Avoid issues with `dynamicIO`
            name: 'next/navigation.js',
            importNames: ['useParams']
          }
        ]
      }
    ],

    // Strict type imports to avoid side effects
    '@typescript-eslint/consistent-type-imports': 'error',
    '@typescript-eslint/consistent-type-exports': 'error',
    '@typescript-eslint/no-import-type-side-effects': 'error',
    '@typescript-eslint/explicit-member-accessibility': 'error',
    'import/no-duplicates': ['error', {'prefer-inline': true}],
    'import/extensions': ['error', {json: 'always'}]
  }
});

import { defineConfig } from 'eslint/config'
import baseConfig from './eslint.config.mjs'

export default defineConfig([
  {
    extends: [baseConfig],
  },
  {
    files: ['**/*.ts', '**/*.tsx'],
    // This override adds type-checked rules.
    // Linting with type-checked rules is very slow and needs a lot of memory,
    // so we exclude non-essential files.
    // NOTE: eslint.config.mjs has a config block that mirrors these
    // `files`/`ignores` to override non-type-checked rules for the same set of
    // files. Keep both in sync if you change the globs.
    ignores: [
      'bench/**/*',
      'examples/**/*',
      'test/**/*',
      '**/*.d.ts',
      'turbopack/**/*',
    ],
    languageOptions: {
      parserOptions: {
        project: true,
      },
    },
    // These rules are added on top of the rules that are declared in
    // the base config for the matching files.
    rules: {
      // TODO: enable in follow-up PR
      '@typescript-eslint/no-floating-promises': 'off',
      '@typescript-eslint/switch-exhaustiveness-check': [
        'error',
        { requireDefaultForNonUnion: true },
      ],
    },
  },
])

import type { HmrMessageSentToBrowser } from '../../../server/dev/hot-reloader-types'

export const REACT_REFRESH_FULL_RELOAD =
  '[Fast Refresh] performing full reload\n\n' +
  "Fast Refresh will perform a full reload when you edit a file that's imported by modules outside of the React rendering tree.\n" +
  'You might have a file which exports a React component but also exports a value that is imported by a non-React component file.\n' +
  'Consider migrating the non-React component export to a separate file and importing it into both files.\n\n' +
  'It is also possible the parent component of the component you edited is a class component, which disables Fast Refresh.\n' +
  'Fast Refresh requires at least one parent function component in your React tree.'

export const REACT_REFRESH_FULL_RELOAD_FROM_ERROR =
  '[Fast Refresh] performing full reload because your application had an unrecoverable error'

export function reportInvalidHmrMessage(
  message: HmrMessageSentToBrowser | MessageEvent<unknown>,
  err: unknown
) {
  console.warn(
    '[HMR] Invalid message: ' +
      JSON.stringify(message) +
      '\n' +
      ((err instanceof Error && err?.stack) || '')
  )
}

import type {ReactNode} from 'react';

export type TranslationValues = Record<
  string,
  // All params that are allowed for basic params as well as operators like
  // `plural`, `select`, `number` and `date`. Note that `Date` is not supported
  // for plain params, but this requires type information from the ICU parser.
  string | number | Date
>;

export type RichTagsFunction = (chunks: ReactNode) => ReactNode;
export type MarkupTagsFunction = (chunks: string) => string;

// We could consider renaming this to `ReactRichTranslationValues` and defining
// it in the `react` namespace if the core becomes useful to other frameworks.
// It would be a breaking change though, so let's wait for now.
export type RichTranslationValues = Record<
  string,
  TranslationValues[string] | RichTagsFunction
>;

export type MarkupTranslationValues = Record<
  string,
  TranslationValues[string] | MarkupTagsFunction
>;
